interface HFSpace {
  id: string;
  name: string;
  status: 'running' | 'building' | 'sleeping' | 'stopped' | 'error';
  url: string;
  sdk: string;
  sdkVersion: string;
  hardware: string;
  createdAt: string;
  lastUpdated: string;
}

interface HFModel {
  id: string;
  name: string;
  taskType: string;
  downloads: number;
  likes: number;
  lastUpdated: string;
  tags: string[];
}

interface HFEndpoint {
  id: string;
  name: string;
  model: string;
  status: 'running' | 'scaling' | 'paused' | 'failed';
  requestsPerMin: number;
  avgLatencyMs: number;
  instanceType: string;
  replicas: number;
  maxReplicas: number;
}

interface HFStats {
  modelsDeployed: number;
  spacesActive: number;
  inferenceEndpoints: number;
  totalDownloads: number;
}

